diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index c06d5c759634..9d7087a63aec 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3009,6 +3009,77 @@ static Value *foldAndOrOfICmpEqZeroAndICmp(ICmpInst *LHS, ICmpInst *RHS,
       Other);
 }

+// (icmp eq X, C) | (icmp ugt (add X, -C), Y) -> icmp uge (add X, -(C+1)), Y
+// (icmp ne X, C) & (icmp ule (add X, -C), Y) -> icmp ult (add X, -(C+1)), Y
+// When C = -1 (all ones), -(C+1) = 0, so the add is omitted:
+// (icmp eq X, -1) | (icmp ugt (add X, 1), Y) -> icmp uge X, Y
+// (icmp ne X, -1) & (icmp ule (add X, 1), Y) -> icmp ult X, Y
+// We know that (X-C) doesn't overflow when X != C, so X-C <= Y  <->  X-(C+1) < Y.
+static Value *foldAndOrOfICmpAllOnesAndICmp(ICmpInst *LHS, ICmpInst *RHS,
+                                             bool IsAnd, bool IsLogical,
+                                             IRBuilderBase &Builder) {
+  ICmpInst::Predicate LPred =
+      IsAnd ? LHS->getInversePredicate() : LHS->getPredicate();
+  ICmpInst::Predicate RPred =
+      IsAnd ? RHS->getInversePredicate() : RHS->getPredicate();
+  Value *LHS0 = LHS->getOperand(0);
+  const APInt *C;
+  // Use m_APIntAllowUndef to handle vector constants with undef elements.
+  if (LPred != ICmpInst::ICMP_EQ ||
+      !match(LHS->getOperand(1), m_APIntAllowUndef(C)) ||
+      !LHS0->getType()->isIntOrIntVectorTy() ||
+      !(LHS->hasOneUse() || RHS->hasOneUse()))
+    return nullptr;
+
+  // Compute the expected add constant: -C.
+  APInt ExpectedAddConst = -(*C);
+
+  Value *Other;
+  // Match: (add X, -C) ugt Y  or  just X ugt Y (when C == 0, -C == 0)
+  if (RPred == ICmpInst::ICMP_UGT) {
+    if (match(RHS->getOperand(0),
+              m_Add(m_Specific(LHS0), m_SpecificIntAllowUndef(ExpectedAddConst))))
+      Other = RHS->getOperand(1);
+    else if (ExpectedAddConst.isZero() && RHS->getOperand(0) == LHS0)
+      Other = RHS->getOperand(1);
+    else
+      return nullptr;
+  }
+  // Match: (add X, -C) ult Y  (swapped: Y ugt (add X, -C))
+  else if (RPred == ICmpInst::ICMP_ULT) {
+    if (match(RHS->getOperand(1),
+              m_Add(m_Specific(LHS0), m_SpecificIntAllowUndef(ExpectedAddConst))))
+      Other = RHS->getOperand(0);
+    else if (ExpectedAddConst.isZero() && RHS->getOperand(1) == LHS0)
+      Other = RHS->getOperand(0);
+    else
+      return nullptr;
+  } else {
+    return nullptr;
+  }
+
+  // Compute the new add constant: -(C+1).
+  APInt NewAddConst = -(*C + 1);
+
+  Value *NewLHS = LHS0;
+  if (!NewAddConst.isZero()) {
+    // If there was an explicit add, ensure it has one use since we're
+    // creating a new add with a different constant.
+    if (!ExpectedAddConst.isZero()) {
+      Instruction *AddI = dyn_cast<Instruction>(
+          RPred == ICmpInst::ICMP_UGT ? RHS->getOperand(0) : RHS->getOperand(1));
+      if (AddI && !AddI->hasOneUse())
+        return nullptr;
+    }
+    NewLHS = Builder.CreateAdd(
+        LHS0, ConstantInt::get(LHS0->getType(), NewAddConst));
+  }
+
+  if (IsLogical)
+    Other = Builder.CreateFreeze(Other);
+  return Builder.CreateICmp(IsAnd ? ICmpInst::ICMP_ULT : ICmpInst::ICMP_UGE,
+                            NewLHS, Other);
+}
 /// Fold (icmp)&(icmp) or (icmp)|(icmp) if possible.
 /// If IsLogical is true, then the and/or is in select form and the transform
 /// must be poison-safe.
@@ -3060,6 +3131,15 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
                                               /*IsLogical*/ false, Builder))
     return V;

+  if (Value *V =
+          foldAndOrOfICmpAllOnesAndICmp(LHS, RHS, IsAnd, IsLogical, Builder))
+    return V;
+  // We can treat logical like bitwise here, because both operands are used on
+  // the LHS, and as such poison from both will propagate.
+  if (Value *V = foldAndOrOfICmpAllOnesAndICmp(RHS, LHS, IsAnd,
+                                               /*IsLogical*/ false, Builder))
+    return V;
+
   if (Value *V =
           foldAndOrOfICmpsWithConstEq(LHS, RHS, IsAnd, IsLogical, Builder, Q))
     return V;

